using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public class PaymentGatewayChargeTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCardAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCard_ReturnsUniqueChargeId()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 25.00m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 25.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task ChargeAsync_NullCardToken_ThrowsArgumentNullException()
    {
        await _gateway.ChargeAsync(null!, 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task ChargeAsync_EmptyCardToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync(string.Empty, 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentOutOfRangeException()
    {
        await _gateway.ChargeAsync("tok_valid_visa", 0m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentOutOfRangeException()
    {
        await _gateway.ChargeAsync("tok_valid_visa", -5.00m);
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [DataRow(0.01)]
    [DataRow(1.00)]
    [DataRow(9999.99)]
    public async Task ChargeAsync_VariousValidAmounts_ReturnsSuccess(double amount)
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", (decimal)amount);

        Assert.IsTrue(result.Success);
    }
}

[TestClass]
public class PaymentGatewayRefundTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);

        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(refund.RefundId));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await _gateway.RefundAsync(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync(string.Empty);
    }

    [TestMethod]
    public async Task RefundAsync_InvalidChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_AlreadyRefundedCharge_ReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);
        await _gateway.RefundAsync(charge.ChargeId);

        var secondRefund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsFalse(secondRefund.Success);
    }

    [TestMethod]
    public async Task RefundAsync_ValidCharge_ReturnsUniqueRefundId()
    {
        var charge1 = await _gateway.ChargeAsync("tok_valid_visa", 30.00m);
        var charge2 = await _gateway.ChargeAsync("tok_valid_visa", 40.00m);

        var refund1 = await _gateway.RefundAsync(charge1.ChargeId);
        var refund2 = await _gateway.RefundAsync(charge2.ChargeId);

        Assert.AreNotEqual(refund1.RefundId, refund2.RefundId);
    }
}

